import './productos.css';
import burgers from "./data-json/burgers.json";
import bebidas from "./data-json/bebidas.json";
import combos from "./data-json/combos.json"
import Tarjeta from './tarjetas-simple-doble/tarjeta';

function Productos() {
  return (
    <div className='productos-cont'>

      <h2>BURGUERS</h2>

      <div className="burguers" id='ham'>
        {
          burgers &&
          burgers.map((elemento) => (
            <Tarjeta key={elemento.id} titulo={elemento.titulo} img={elemento.img} precio={elemento.precio} />
          ))
        }
      </div>

      <h2>BEBIDAS</h2>

      <div className='bebidas' id='beb'>
        {
          bebidas &&
          bebidas.map((elemento) => (
            <Tarjeta key={elemento.id} titulo={elemento.titulo} img={elemento.img} precio={elemento.precio} />
          ))
        }
      </div>

      <h2>COMBOS</h2>

      <div className='combos'>
        {
          combos &&
          combos.map((elemento) => (
            <Tarjeta key={elemento.id} titulo={elemento.titulo} img={elemento.img} precio={elemento.precio} />
          ))
        }
      </div>
    </div>
  );
}

export default Productos;
